text:
bug_type: null_pointer_guard
pattern_name: null_pointer_guard
trigger_signals: null_pointer, nullable, guard_clause
explanation: Add explicit null guard before chained dereference to prevent runtime NPE.
patch_diff:
diff --git a/src/main/java/com/example/UserService.java b/src/main/java/com/example/UserService.java
--- a/src/main/java/com/example/UserService.java
+++ b/src/main/java/com/example/UserService.java
@@ -1,5 +1,8 @@
 class UserService {
     String displayName(User user) {
+        if (user == null || user.getProfile() == null) {
+            return "";
+        }
         return user.getProfile().getName();
     }
 }

bug_type: sql_injection_parameterized
pattern_name: sql_injection_parameterized
trigger_signals: sql_injection, string_concat_sql, prepared_statement
explanation: Replace string-concatenated SQL with parameterized query to prevent injection.
patch_diff:
diff --git a/src/main/java/com/example/UserDao.java b/src/main/java/com/example/UserDao.java
--- a/src/main/java/com/example/UserDao.java
+++ b/src/main/java/com/example/UserDao.java
@@ -8,3 +8,5 @@ class UserDao {
-    String sql = "select * from users where id=" + userId;
-    return stmt.executeQuery(sql);
+    PreparedStatement ps = conn.prepareStatement("select * from users where id=?");
+    ps.setString(1, userId);
+    return ps.executeQuery();
 }

bug_type: n_plus_one_batch_query
pattern_name: n_plus_one_batch_query
trigger_signals: n_plus_one, loop_query, batch_fetch
explanation: Collapse per-item lookup into one batch query to reduce round-trips.
patch_diff:
diff --git a/src/main/java/com/example/UserBatchService.java b/src/main/java/com/example/UserBatchService.java
--- a/src/main/java/com/example/UserBatchService.java
+++ b/src/main/java/com/example/UserBatchService.java
@@ -6,3 +6,5 @@ class UserBatchService {
-    for (Long id : ids) {
-        users.add(repo.findById(id).orElse(null));
-    }
+    Map<Long, User> usersById = repo.findAllById(ids).stream()
+        .collect(Collectors.toMap(User::getId, u -> u));
+    for (Long id : ids) { users.add(usersById.get(id)); }
 }

bug_type: resource_leak_try_with_resources
pattern_name: resource_leak_try_with_resources
trigger_signals: resource_leak, stream_not_closed, try_with_resources
explanation: Wrap stream in try-with-resources to guarantee close on success/failure.
patch_diff:
diff --git a/src/main/java/com/example/FileReaderUtil.java b/src/main/java/com/example/FileReaderUtil.java
--- a/src/main/java/com/example/FileReaderUtil.java
+++ b/src/main/java/com/example/FileReaderUtil.java
@@ -4,2 +4,4 @@ class FileReaderUtil {
-    InputStream in = new FileInputStream(path);
-    return in.read();
+    try (InputStream in = new FileInputStream(path)) {
+        return in.read();
+    }
 }

bug_type: missing_return_string
pattern_name: missing_return_string
trigger_signals: missing_return, return_type_string, not_all_code_paths_return
explanation: Method declares String return type; add explicit fallback return on uncovered control-flow path to satisfy compiler.
patch_diff:
diff --git a/src/main/java/com/example/UserLabeler.java b/src/main/java/com/example/UserLabeler.java
--- a/src/main/java/com/example/UserLabeler.java
+++ b/src/main/java/com/example/UserLabeler.java
@@ -3,5 +3,6 @@ class UserLabeler {
     String label(int score) {
         if (score > 0) {
             return "ok";
         }
+        return "unknown";
     }
 }

bug_type: missing_return_boolean
pattern_name: missing_return_boolean
trigger_signals: missing_return, return_type_boolean, compile_error
explanation: Compiler requires boolean for all paths; add deterministic default false branch.
patch_diff:
diff --git a/src/main/java/com/example/FeatureSwitch.java b/src/main/java/com/example/FeatureSwitch.java
--- a/src/main/java/com/example/FeatureSwitch.java
+++ b/src/main/java/com/example/FeatureSwitch.java
@@ -5,5 +5,6 @@ class FeatureSwitch {
         if (flag.startsWith("exp")) {
             return true;
         }
+        return false;
     }
 }

bug_type: missing_return_numeric
pattern_name: missing_return_numeric
trigger_signals: missing_return, numeric_return, int_method
explanation: Add numeric fallback to satisfy declared int return type and keep deterministic retry baseline.
patch_diff:
diff --git a/src/main/java/com/example/RetryPolicy.java b/src/main/java/com/example/RetryPolicy.java
--- a/src/main/java/com/example/RetryPolicy.java
+++ b/src/main/java/com/example/RetryPolicy.java
@@ -3,5 +3,6 @@ class RetryPolicy {
     int retries(String level) {
         if ("high".equals(level)) {
             return 5;
         }
+        return 1;
     }
 }

bug_type: incomplete_return_paths
pattern_name: incomplete_return_paths
trigger_signals: not_all_code_paths_return, if_else_missing_branch, compile_failed_after_repair
explanation: Control-flow graph has uncovered path when both conditions false; add explicit final return.
patch_diff:
diff --git a/src/main/java/com/example/DiscountCalculator.java b/src/main/java/com/example/DiscountCalculator.java
--- a/src/main/java/com/example/DiscountCalculator.java
+++ b/src/main/java/com/example/DiscountCalculator.java
@@ -6,5 +6,6 @@ class DiscountCalculator {
         } else if (flashSale) {
             return 10;
         }
+        return 0;
     }
 }

bug_type: uninitialized_local
pattern_name: uninitialized_local
trigger_signals: variable_might_not_have_been_initialized, local_variable, compile_error
explanation: Initialize local variable with safe default before conditional assignment.
patch_diff:
diff --git a/src/main/java/com/example/GreetingBuilder.java b/src/main/java/com/example/GreetingBuilder.java
--- a/src/main/java/com/example/GreetingBuilder.java
+++ b/src/main/java/com/example/GreetingBuilder.java
@@ -2,7 +2,7 @@ class GreetingBuilder {
     String build(boolean formal) {
-        String prefix;
+        String prefix = "Hi";
         if (formal) {
             prefix = "Dear";
         }
         return prefix + " user";
     }
 }

bug_type: simple_type_mismatch
pattern_name: simple_type_mismatch
trigger_signals: incompatible_types, string_to_int, compile_error
explanation: Resolve primitive type mismatch by explicit parse conversion.
patch_diff:
diff --git a/src/main/java/com/example/OrderMapper.java b/src/main/java/com/example/OrderMapper.java
--- a/src/main/java/com/example/OrderMapper.java
+++ b/src/main/java/com/example/OrderMapper.java
@@ -1,5 +1,5 @@
 class OrderMapper {
     int toId(String rawId) {
-        return rawId;
+        return Integer.parseInt(rawId);
     }
 }
